20	class LogicalModels;
21	
22	class PreClusterDelayCalculator : public tatum::DelayCalculator {
23	  public:
24	    PreClusterDelayCalculator(const AtomNetlist& netlist,
25	                              const AtomLookup& netlist_lookup,
26	                              const LogicalModels& models,
27	                              const vtr::vector<AtomPinId, float>& timing_arc_delays,
28	                              const Prepacker& prepacker) noexcept
29	        : netlist_(netlist)
30	        , netlist_lookup_(netlist_lookup)
31	        , models_(models)
32	        , timing_arc_delays_(timing_arc_delays)
33	        , prepacker_(prepacker) {
34	
35	        // Timing arcs are uniquely identified by sink pins, ensure that every
36	        // timing arc delay has an entry for each pin in the atom netlist.
37	        VTR_ASSERT(timing_arc_delays.size() == netlist_.pins().size());
38	    }
39	
40	    tatum::Time max_edge_delay(const tatum::TimingGraph& tg, tatum::EdgeId edge_id) const override {
41	        tatum::NodeId src_node = tg.edge_src_node(edge_id);
42	        tatum::NodeId sink_node = tg.edge_sink_node(edge_id);
43	
44	        auto edge_type = tg.edge_type(edge_id);
45	
46	        if (edge_type == tatum::EdgeType::PRIMITIVE_COMBINATIONAL) {
47	            return prim_comb_delay(tg, src_node, sink_node);
48	        } else if (edge_type == tatum::EdgeType::PRIMITIVE_CLOCK_LAUNCH) {
49	            return prim_tcq_delay(tg, src_node, sink_node);
50	        } else {
51	            VTR_ASSERT(edge_type == tatum::EdgeType::INTERCONNECT);
52	
53	            // Get the sink pin for this timing edge. This is used to get the
54	            // delay for the timing arc that goes through this sink pin.
55	            AtomPinId atom_sink_pin = netlist_lookup_.tnode_atom_pin(sink_node);
56	            VTR_ASSERT_SAFE(atom_sink_pin.is_valid());
57	            VTR_ASSERT_SAFE(netlist_.pin_type(atom_sink_pin) == PinType::SINK);
58	
59	            // External net delay
60	            return tatum::Time(timing_arc_delays_[atom_sink_pin]);
61	        }
62	    }
63	
64	    tatum::Time setup_time(const tatum::TimingGraph& tg, tatum::EdgeId edge_id) const override {
65	        tatum::NodeId src_node = tg.edge_src_node(edge_id);
66	        tatum::NodeId sink_node = tg.edge_sink_node(edge_id);
67	        auto edge_type = tg.edge_type(edge_id);
68	
69	        VTR_ASSERT_MSG(tg.node_type(src_node) == tatum::NodeType::CPIN, "Edge setup time only valid if source node is a CPIN");
70	        VTR_ASSERT_MSG(tg.node_type(sink_node) == tatum::NodeType::SINK, "Edge setup time only valid if sink node is a SINK");
71	        VTR_ASSERT(edge_type == tatum::EdgeType::PRIMITIVE_CLOCK_CAPTURE);
72	
73	        AtomPinId sink_pin = netlist_lookup_.tnode_atom_pin(sink_node);
74	        VTR_ASSERT(sink_pin);
75	
76	        const t_pb_graph_pin* gpin = find_pb_graph_pin(sink_pin);
77	        VTR_ASSERT(gpin->type == PB_PIN_SEQUENTIAL);
78	
79	        return tatum::Time(gpin->tsu);
80	    }
81	
82	    tatum::Time min_edge_delay(const tatum::TimingGraph& tg, tatum::EdgeId edge_id) const override {
83	        //Currently return the same delay
84	        //TODO: use true min delay
85	        return max_edge_delay(tg, edge_id);
86	    }
87	
88	    tatum::Time hold_time(const tatum::TimingGraph& tg, tatum::EdgeId edge_id) const override {
89	        //Currently return the same as hold time
90	        //TODO: use true hold time
91	        return setup_time(tg, edge_id);
92	    }
93	
94	  private:
95	    //TODO: use generic AtomDelayCalc class to avoid code duplication
96	
97	    tatum::Time prim_tcq_delay(const tatum::TimingGraph& tg, tatum::NodeId src_node, tatum::NodeId sink_node) const {
98	        VTR_ASSERT_MSG(tg.node_type(src_node) == tatum::NodeType::CPIN
99	                           && tg.node_type(sink_node) == tatum::NodeType::SOURCE,
100	                       "Tcq only defined from CPIN to SOURCE");
101	
102	        AtomPinId sink_pin = netlist_lookup_.tnode_atom_pin(sink_node);
103	        VTR_ASSERT(sink_pin);
104	
105	        const t_pb_graph_pin* gpin = find_pb_graph_pin(sink_pin);
106	        VTR_ASSERT(gpin->type == PB_PIN_SEQUENTIAL);
107	
108	        //Clock-to-q delay marked on the SOURCE node (the sink node of this edge)
109	        auto tco = tatum::Time(gpin->tco_max);
110	
111	        VTR_ASSERT_MSG(tco.valid(), "Found no primitive clock-to-q delay");
112	
113	        return tco;
114	    }
115	
116	    tatum::Time prim_comb_delay(const tatum::TimingGraph& tg, tatum::NodeId src_node, tatum::NodeId sink_node) const {
117	        auto src_node_type = tg.node_type(src_node);
118	        auto sink_node_type = tg.node_type(sink_node);
119	        VTR_ASSERT_MSG((src_node_type == tatum::NodeType::IPIN && sink_node_type == tatum::NodeType::OPIN)
120	                           || (src_node_type == tatum::NodeType::SOURCE && sink_node_type == tatum::NodeType::SINK)
121	                           || (src_node_type == tatum::NodeType::SOURCE && sink_node_type == tatum::NodeType::OPIN)
122	                           || (src_node_type == tatum::NodeType::CPIN && sink_node_type == tatum::NodeType::OPIN)
123	                           || (src_node_type == tatum::NodeType::IPIN && sink_node_type == tatum::NodeType::SINK),
124	                       "Primitive combinational delay must be between {SOURCE, IPIN} and {SINK, OPIN}, or CPIN/OPIN");
125	
126	        //Primitive internal combinational delay
127	        AtomPinId input_pin = netlist_lookup_.tnode_atom_pin(src_node);
128	        VTR_ASSERT(input_pin);
129	        const t_pb_graph_pin* input_gpin = find_pb_graph_pin(input_pin);
130	
131	        AtomPinId output_pin = netlist_lookup_.tnode_atom_pin(sink_node);
132	        VTR_ASSERT(output_pin);
133	        const t_pb_graph_pin* output_gpin = find_pb_graph_pin(output_pin);
134	
135	        tatum::Time time;
136	        for (int i = 0; i < input_gpin->num_pin_timing; ++i) {
137	            const t_pb_graph_pin* sink_gpin = input_gpin->pin_timing[i];
138	
139	            if (sink_gpin == output_gpin) {
140	                time = tatum::Time(input_gpin->pin_timing_del_max[i]);
141	                break;
142	            }
143	        }
144	
145	        VTR_ASSERT_MSG(time.valid(), "Found no primitive combinational delay for edge");
146	
147	        return time;
148	    }
149	
150	    const t_pb_graph_pin* find_pb_graph_pin(const AtomPinId pin) const {
151	        AtomBlockId blk = netlist_.pin_block(pin);
152	
153	        const t_pb_graph_node* pb_gnode = prepacker_.get_expected_lowest_cost_pb_gnode(blk);
154	
155	        AtomPortId port = netlist_.pin_port(pin);
156	        const t_model_ports* model_port = netlist_.port_model(port);
157	        int ipin = netlist_.pin_port_bit(pin);
158	
159	        const t_pb_graph_pin* gpin = get_pb_graph_node_pin_from_model_port_pin(model_port, ipin, pb_gnode);
160	        VTR_ASSERT(gpin);
161	
162	        return gpin;
163	    }
164	
165	    const t_pb_graph_pin* find_associated_clock_pin(const AtomPinId io_pin) const {
166	        const t_pb_graph_pin* io_gpin = find_pb_graph_pin(io_pin);
167	
168	        const t_pb_graph_pin* clock_gpin = io_gpin->associated_clock_pin;
169	
170	        if (!clock_gpin) {
171	            AtomBlockId blk = netlist_.pin_block(io_pin);
172	            std::string model_name = models_.get_model(netlist_.block_model(blk)).name;
173	            VPR_FATAL_ERROR(VPR_ERROR_TIMING, "Failed to find clock pin associated with pin '%s' (model '%s')", netlist_.pin_name(io_pin).c_str(), model_name.c_str());
174	        }
175	        return clock_gpin;
176	    }
177	
178	  private:
179	    const AtomNetlist& netlist_;
180	    const AtomLookup& netlist_lookup_;
181	    const LogicalModels& models_;
182	    const vtr::vector<AtomPinId, float>& timing_arc_delays_;
183	    const Prepacker& prepacker_;
184	};
