1	/**
2	 * @file
3	 * @author  Alex Singer
4	 * @date    February 2026
5	 * @brief   Functions for reading an SDC file and updating the timing constraints
6	 *          on the netlist (in Tatum).
7	 * 
8	 * This file uses LibSDCParse to parse the SDC constraints provided. It uses a TCL
9	 * interpreter to parse each of the commands in the SDC file. This file declares a
10	 * callback object which provides callback functions which will be called when
11	 * different SDC constraints are parsed.
12	 * 
13	 * Internally, LibSDCParse maintains a database of netlist objects which may be
14	 * parsed. In the start_parse callback, we populate this internal database with
15	 * all of the netlist objects that we expect users to refer to in their SDC files.
16	 * 
17	 * If no SDC file is provided, the parser is never invoked (the callback is never
18	 * constructed), and default timing constraints are applied.
19	 */
20	
21	#include "read_sdc.h"
22	
23	#include <filesystem>
24	#include <limits>
25	#include <regex>
26	#include <unordered_map>
