40	#include "atom_netlist_utils.h"
41	#include "atom_lookup.h"
42	
43	void apply_default_timing_constraints(const AtomNetlist& netlist,
44	                                      const AtomLookup& lookup,
45	                                      const LogicalModels& models,
46	                                      tatum::TimingConstraints& timing_constraints);
47	
48	void apply_combinational_default_timing_constraints(const AtomNetlist& netlist,
49	                                                    const AtomLookup& lookup,
50	                                                    tatum::TimingConstraints& timing_constraints);
51	
52	void apply_single_clock_default_timing_constraints(const AtomNetlist& netlist,
53	                                                   const AtomLookup& lookup,
54	                                                   const AtomPinId clock_driver,
55	                                                   tatum::TimingConstraints& timing_constraints);
56	
57	void apply_multi_clock_default_timing_constraints(const AtomNetlist& netlist,
58	                                                  const AtomLookup& lookup,
59	                                                  const std::set<AtomPinId>& clock_drivers,
60	                                                  tatum::TimingConstraints& timing_constraints);
61	
62	void mark_constant_generators(const AtomNetlist& netlist,
63	                              const AtomLookup& lookup,
64	                              tatum::TimingConstraints& tc);
65	
66	void constrain_all_ios(const AtomNetlist& netlist,
67	                       const AtomLookup& lookup,
68	                       tatum::TimingConstraints& tc,
69	                       tatum::DomainId input_domain,
70	                       tatum::DomainId output_domain,
71	                       tatum::Time input_delay,
72	                       tatum::Time output_delay);
73	
74	std::map<std::string, AtomPinId> find_netlist_primary_ios(const AtomNetlist& netlist);
75	std::string orig_blif_name(std::string name);
