79	class SdcParseCallback : public sdcparse::Callback {
80	  public:
81	    SdcParseCallback(const AtomNetlist& netlist,
82	                     const AtomLookup& lookup,
83	                     const LogicalModels& models,
84	                     tatum::TimingConstraints& timing_constraints,
85	                     tatum::TimingGraph& tg)
86	        : netlist_(netlist)
87	        , lookup_(lookup)
88	        , models_(models)
89	        , tc_(timing_constraints)
90	        , tg_(tg) {}
91	
92	  public: //sdcparse::Callback interface
93	    //Start of parsing
94	    void start_parse() override {
95	        netlist_clock_drivers_ = find_netlist_logical_clock_drivers(netlist_, models_);
96	        netlist_primary_ios_ = find_netlist_primary_ios(netlist_);
97	
98	        // Create the port objects in the object database.
99	        std::unordered_set<AtomPinId> ports;
100	        for (const auto& p : netlist_primary_ios_) {
101	            sdcparse::PortDirection port_dir;
102	            switch (netlist_.pin_type(p.second)) {
103	                case PinType::DRIVER:
104	                    port_dir = sdcparse::PortDirection::INPUT;
105	                    break;
106	                case PinType::SINK:
107	                    port_dir = sdcparse::PortDirection::OUTPUT;
108	                    break;
109	                default:
110	                    port_dir = sdcparse::PortDirection::UNKNOWN;
111	                    break;
112	            }
113	
114	            bool is_clock_driver = false;
115	            if (netlist_clock_drivers_.contains(p.second))
116	                is_clock_driver = true;
117	
118	            sdcparse::ObjectId port_id = obj_database.create_port_object(p.first, port_dir, is_clock_driver);
119	            object_to_port_id_[port_id] = p.second;
120	            ports.insert(p.second);
121	        }
122	
123	        // Create the pin objects in the object database.
124	        for (AtomPinId pin : netlist_.pins()) {
125	            // Ports are not pins.
126	            if (ports.count(pin) != 0)
127	                continue;
128	
129	            const std::string& pin_name = netlist_.pin_name(pin);
130	
131	            bool is_clock_driver = false;
132	            if (netlist_clock_drivers_.contains(pin))
133	                is_clock_driver = true;
134	
135	            sdcparse::ObjectId pin_id = obj_database.create_pin_object(pin_name, is_clock_driver);
136	            object_to_pin_id_[pin_id] = pin;
137	        }
138	
139	        // Create the net objects in the object database.
140	        for (AtomNetId net : netlist_.nets()) {
141	            const std::string& net_name = netlist_.net_name(net);
142	            for (const std::string& net_alias : netlist_.net_aliases(net_name)) {
143	                sdcparse::ObjectId net_id = obj_database.create_net_object(net_alias);
144	                object_to_net_id_[net_id] = net;
145	            }
146	        }
147	    }
148	
149	    //Sets current filename
150	    void filename(std::string fname) override { fname_ = fname; }
151	
152	    //Sets current line number
153	    void lineno(int line_num) override { lineno_ = line_num; }
154	
155	    //Individual commands
156	    void create_clock(const sdcparse::CreateClock& cmd) override {
157	        num_commands_++;
158	
159	        if (cmd.add && cmd.name.empty()) {
160	            vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
161	                      "-add requires -name for create_clock");
162	        }
163	
164	        if (cmd.is_virtual) {
165	            if (cmd.name.empty()) {
166	                vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
167	                          "clocks with no targets must have a name");
168	            }
169	
170	            // Virtual clocks should have no targets
171	            if (!cmd.targets.empty()) {
172	                vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
173	                          "Virtual clock definition (i.e. with '-name') should not have targets");
174	            }
175	        } else {
176	            // Check that all of the objects are valid types.
177	            bool targets_valid = check_objects(cmd.targets,
178	                                               {sdcparse::ObjectType::Port, sdcparse::ObjectType::Pin, sdcparse::ObjectType::Net});
179	            if (!targets_valid) {
180	                vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
181	                          "create_clock command only supports ports, pins, and nets");
182	            }
183	        }
184	
185	        if (cmd.is_virtual) {
186	            // Create a virtual clock
187	            create_clock_object(cmd.name, tatum::NodeId::INVALID(), cmd);
188	            return;
189	        }
190	
191	        // Collect all of the target pins and their names. The names of the objects
192	        // are used for the names of the clocks when no name is provided.
193	        std::map<AtomPinId, std::string> target_pins = get_clock_target_pins(cmd.targets);
194	
195	        // Check that if the clock is named, there is only one unique clock driver.
196	        if (target_pins.size() > 1 && !cmd.name.empty()) {
197	            for (const auto& p : target_pins) {
198	                VTR_LOG("Name: %s\n", p.second.c_str());
199	            }
200	            // NOTE: The reason this is not supported is because we currently
201	            //       create unique clock domains for each target. This may not
202	            //       be standard and they cannot all be named the same thing.
203	            vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
204	                      "named clocks with more than 1 unique target are not supported for create_clock");
205	        }
206	
207	        // Create a netlist clock for every target pin.
208	        for (const auto& p : target_pins) {
209	            AtomPinId clock_pin = p.first;
210	            const std::string& object_name = p.second;
211	
212	            // Get the name of the clock. If no name is provided, the name of the port/pin is used.
213	            std::string clock_name;
214	            if (cmd.name.empty()) {
215	                clock_name = object_name;
216	            } else {
217	                VTR_ASSERT(target_pins.size() == 1);
218	                clock_name = cmd.name;
219	            }
220	
221	            // Get the clock source associated with this pin.
222	            tatum::NodeId clock_source = get_clock_source(clock_pin);
223	            VTR_ASSERT(clock_source.is_valid());
224	
225	            // Create netlist clock (a clock net which ultimately drives a
226	            // clock pin on some block in the design netlist)
227	            create_clock_object(clock_name, clock_source, cmd);
228	        }
229	    }
