231	    void create_generated_clock(const sdcparse::CreateGeneratedClock& cmd) override {
232	        num_commands_++;
233	
234	        // Check that the arguments to the command are valid.
235	        if (cmd.add && cmd.name.empty()) {
236	            vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
237	                      "-add requires -name for create_generated_clock");
238	        }
239	
240	        if (!std::isnan(cmd.phase) && !std::isnan(cmd.offset)) {
241	            vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
242	                      "-phase and -offset are mutually exclusive for create_generated_clock");
243	        }
244	
245	        if (!cmd.edge_shift.empty() && cmd.edges.empty()) {
246	            vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
247	                      "-edge_shift requires -edges for create_generated_clock");
248	        }
249	
250	        if (!cmd.edges.empty()) {
251	            if (cmd.edges.size() != 3) {
252	                vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
253	                          "-edges must contain exactly 3 edge indices for create_generated_clock");
254	            }
255	            if (!cmd.edge_shift.empty() && cmd.edge_shift.size() != cmd.edges.size()) {
256	                vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
257	                          "-edge_shift must contain the same number of values as -edges for create_generated_clock");
258	            }
259	            for (double edge : cmd.edges) {
260	                if (edge != std::floor(edge)) {
261	                    vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
262	                              "-edges values must be integers for create_generated_clock");
263	                }
264	                if (edge < 1.0) {
265	                    vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
266	                              "-edges indices are 1-based; index must be >= 1 for create_generated_clock");
267	                }
268	            }
269	            if (!(cmd.edges[0] < cmd.edges[1] && cmd.edges[1] < cmd.edges[2])) {
270	                vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
271	                          "-edges must be strictly increasing for create_generated_clock");
272	            }
273	            if (!std::isnan(cmd.phase) || !std::isnan(cmd.offset)) {
274	                vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
275	                          "-phase and -offset cannot be combined with -edges for create_generated_clock");
276	            }
277	        }
278	
279	        if (cmd.sources.empty()) {
280	            vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
281	                      "-source is required for create_generated_clock");
282	        }
283	
284	        if (cmd.edges.empty() && cmd.divide_by == sdcparse::UNINITIALIZED_INT && cmd.multiply_by == sdcparse::UNINITIALIZED_INT
285	            && std::isnan(cmd.phase) && std::isnan(cmd.offset)) {
286	            vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
287	                      "One of -divide_by, -multiply_by, -edges, -phase, or -offset is required for create_generated_clock");
288	        }
289	        if ((cmd.divide_by != sdcparse::UNINITIALIZED_INT && cmd.divide_by <= 0) || (cmd.multiply_by != sdcparse::UNINITIALIZED_INT && cmd.multiply_by <= 0)) {
290	            vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
291	                      "-divide_by and -multiply_by must be strictly positive for create_generated_clock");
292	        }
293	
294	        if (cmd.invert) {
295	            if (!cmd.edges.empty()) {
296	                vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
297	                          "-invert cannot be combined with -edges for create_generated_clock");
298	            }
299	            if (cmd.divide_by == sdcparse::UNINITIALIZED_INT && cmd.multiply_by == sdcparse::UNINITIALIZED_INT
300	                && std::isnan(cmd.phase) && std::isnan(cmd.offset)) {
301	                vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
302	                          "-invert can only be used for clock multiplication, division, phase shift, or offset.");
303	            }
304	        }
305	
306	        if (!std::isnan(cmd.duty_cycle)) {
307	            if (cmd.multiply_by == sdcparse::UNINITIALIZED_INT) {
308	                vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
309	                          "-duty_cycle can only be used for clock multiplication.");
310	            }
311	        }
312	
313	        // If no targets are provided, the generated clock is virtual.
314	        bool is_virtual = cmd.targets.empty();
315	        if (is_virtual) {
316	            // Virtual clocks must be named.
317	            if (cmd.name.empty()) {
318	                vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
319	                          "clocks with no targets (i.e. virtual clocks) must have a name");
320	            }
321	        } else {
322	            // Check that all of the objects are valid types.
323	            bool targets_valid = check_objects(cmd.targets, {sdcparse::ObjectType::Port, sdcparse::ObjectType::Pin, sdcparse::ObjectType::Net});
324	            if (!targets_valid) {
325	                vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
326	                          "create_generated_clock command only supports ports, pins, and nets");
327	            }
328	        }
329	
330	        // Get the source clock.
331	        //  Get the clock pins referred to by the source argument.
332	        std::map<AtomPinId, std::string> source_clock_pins = get_clock_target_pins(cmd.sources);
333	        if (source_clock_pins.size() > 1) {
334	            vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
335	                      "create_generated_clock can only have 1 source clock, multiple found.");
336	        }
337	        if (source_clock_pins.empty()) {
338	            vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
339	                      "Cannot find source pin for create_generated_clock");
340	        }
341	        //  Get the clock domain for the found pins.
342	        AtomPinId source_clock_pin = source_clock_pins.begin()->first;
343	        tatum::NodeId source_clock_tnode = get_clock_source(source_clock_pin);
344	        tatum::DomainId source_domain_id;
345	        if (cmd.master_clock.is_valid()) {
346	            // -master_clock disambiguates which domain to derive from when multiple
347	            // clocks share the source pin (e.g. create_clock -add was used on it).
348	            auto it = object_to_clock_id_.find(cmd.master_clock);
349	            if (it == object_to_clock_id_.end()) {
350	                vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
351	                          "Cannot find -master_clock for create_generated_clock. "
352	                          "Make sure it has been created using create_clock.");
353	            }
354	            source_domain_id = it->second;
355	            if (tc_.clock_domain_source_node(source_domain_id) != source_clock_tnode) {
356	                vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
357	                          "-master_clock does not originate at the specified -source pin "
358	                          "for create_generated_clock.");
359	            }
360	        } else {
361	            for (tatum::DomainId domain_id : tc_.clock_domains()) {
362	                if (tc_.clock_domain_source_node(domain_id) == source_clock_tnode) {
363	                    if (source_domain_id.is_valid()) {
364	                        vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
365	                                  "create_generated_clock source pin matches multiple clocks; "
366	                                  "use -master_clock to specify which one.");
367	                    }
368	                    source_domain_id = domain_id;
369	                }
370	            }
371	        }
372	        if (!source_domain_id.is_valid()) {
373	            vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
374	                      "Cannot find source clock for create_generated_clock. "
375	                      "Make sure that the source clock has been created using create_clock.");
376	        }
377	        //  Find the command that created this clock.
378	        VTR_ASSERT(sdc_clocks_.contains(source_domain_id));
379	        const sdcparse::CreateClock& source_clock_cmd = sdc_clocks_[source_domain_id];
380	
381	        // Get the generated clock period and rise/fall edges.
382	        double source_clock_period = source_clock_cmd.period;
383	        double generated_clock_period;
384	        double generated_rise_edge;
385	        double generated_fall_edge;
386	
387	        if (!cmd.edges.empty()) {
388	            // Edges mode: convert 1-based master clock edge indices to absolute times,
389	            // optionally apply per-edge shifts, then derive the waveform.
390	            //
391	            // Edge index n maps to the master clock timeline:
392	            //   odd  n → source_rise_edge + ((n-1)/2) * source_period  (rising edge)
393	            //   even n → source_fall_edge + ((n-1)/2) * source_period  (falling edge)
394	            auto edge_index_to_time = [&](double edge_idx) -> double {
395	                int n = static_cast<int>(edge_idx);
396	                int cycle = (n - 1) / 2;
397	                return (n % 2 == 1 ? source_clock_cmd.rise_edge : source_clock_cmd.fall_edge)
398	                       + cycle * source_clock_period;
399	            };
400	
401	            double shift0 = cmd.edge_shift.empty() ? 0.0 : cmd.edge_shift[0];
402	            double shift1 = cmd.edge_shift.empty() ? 0.0 : cmd.edge_shift[1];
403	            double shift2 = cmd.edge_shift.empty() ? 0.0 : cmd.edge_shift[2];
404	
405	            double t0 = edge_index_to_time(cmd.edges[0]) + shift0;
406	            double t1 = edge_index_to_time(cmd.edges[1]) + shift1;
407	            double t2 = edge_index_to_time(cmd.edges[2]) + shift2;
408	
409	            generated_rise_edge = t0;
410	            generated_fall_edge = t1;
411	            generated_clock_period = t2 - t0;
412	
413	            if (generated_clock_period <= 0.0) {
414	                vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
415	                          "Generated clock period derived from -edges must be strictly positive");
416	            }
417	        } else {
418	            // Determine the generated clock period.
419	            // The rise edge is stored as-is, even if it falls outside the generated clock's period.
420	            // Normalization is handled at the point of use in calculate_launch_to_capture_edge_times().
421	            if (cmd.divide_by != sdcparse::UNINITIALIZED_INT) {
422	                // Dividing the frequency means multiplying the period.
423	                generated_clock_period = source_clock_period * static_cast<double>(cmd.divide_by);
424	            } else if (cmd.multiply_by != sdcparse::UNINITIALIZED_INT) {
425	                // Multiplying the frequency means dividing the period.
426	                generated_clock_period = source_clock_period / static_cast<double>(cmd.multiply_by);
427	            } else {
428	                // -phase or -offset alone: the period is unchanged from the master.
429	                generated_clock_period = source_clock_period;
430	            }
431	
432	            generated_rise_edge = source_clock_cmd.rise_edge;
433	            if (cmd.divide_by != sdcparse::UNINITIALIZED_INT || cmd.multiply_by != sdcparse::UNINITIALIZED_INT) {
434	                // Per SDC spec, if no duty cycle is specified, the generated clock defaults to 50%.
435	                double duty_cycle = 50.0;
436	                // If a duty cycle was specified (only valid for multiplication, enforced above), use it.
437	                if (!std::isnan(cmd.duty_cycle)) {
438	                    duty_cycle = cmd.duty_cycle;
439	                }
440	                generated_fall_edge = generated_rise_edge + generated_clock_period * (duty_cycle / 100.0);
441	            } else {
442	                // -phase or -offset alone: inherit the master's duty cycle.
443	                generated_fall_edge = source_clock_cmd.fall_edge;
444	            }
445	
446	            // Apply a phase shift (in degrees) or a fixed time offset (in ns) to both edges.
447	            // The period is unaffected; only the waveform position shifts.
448	            if (!std::isnan(cmd.phase)) {
449	                double shift = (cmd.phase / 360.0) * source_clock_period;
450	                generated_rise_edge += shift;
451	                generated_fall_edge += shift;
452	            } else if (!std::isnan(cmd.offset)) {
453	                generated_rise_edge += cmd.offset;
454	                generated_fall_edge += cmd.offset;
455	            }
456	
457	            // If the clock is inverted, we swap the rising and falling edges.
458	            if (cmd.invert) {
459	                std::swap(generated_rise_edge, generated_fall_edge);
460	            }
461	        }
462	
463	        if (is_virtual) {
464	            // Create a virtual clock.
465	            // See the note below, this cmd is only used to lookup information
466	            // on the clocks.
467	            // TODO: Make this interface better.
468	            sdcparse::CreateClock new_create_clock_cmd;
469	            new_create_clock_cmd.add = false;
470	            new_create_clock_cmd.is_virtual = true;
471	            new_create_clock_cmd.name = cmd.name;
472	            new_create_clock_cmd.targets = cmd.targets;
473	            new_create_clock_cmd.period = generated_clock_period;
474	            new_create_clock_cmd.rise_edge = generated_rise_edge;
475	            new_create_clock_cmd.fall_edge = generated_fall_edge;
476	
477	            create_clock_object(cmd.name, tatum::NodeId::INVALID(), new_create_clock_cmd);
478	        }
479	
480	        // Get the targets pins.
481	        std::map<AtomPinId, std::string> target_pins = get_clock_target_pins(cmd.targets);
482	
483	        // Check that if the clock is named, there is only one unique clock driver.
484	        if (target_pins.size() > 1 && !cmd.name.empty()) {
485	            for (const auto& p : target_pins) {
486	                VTR_LOG("Name: %s\n", p.second.c_str());
487	            }
488	            // NOTE: The reason this is not supported is because we currently
489	            //       create unique clock domains for each target. This may not
490	            //       be standard and they cannot all be named the same thing.
491	            //       This is the same issue in create_clock.
492	            vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
493	                      "named clocks with more than 1 unique target are not supported for create_generated_clock");
494	        }
495	
496	        // Create a netlist clock for every target pin.
497	        for (const auto& p : target_pins) {
498	            AtomPinId clock_pin = p.first;
499	            const std::string& object_name = p.second;
500	
501	            // Get the name of the clock. If no name is provided, the name of the object (clock pin, port, or net) is used.
502	            std::string clock_name;
503	            if (cmd.name.empty()) {
504	                clock_name = object_name;
505	            } else {
506	                VTR_ASSERT(target_pins.size() == 1);
507	                clock_name = cmd.name;
508	            }
509	
510	            // Get the clock source associated with this pin.
511	            tatum::NodeId clock_source = get_clock_source(clock_pin);
512	            VTR_ASSERT(clock_source.is_valid());
513	
514	            // Create equivalent create_clock commands for this generated clock.
515	            // NOTE: This is a bit of a hack, but the command is used throughout
516	            //       this code to quickly lookup information on the clock.
517	            // TODO: Consider using a better storage for this information instead
518	            //       of the command.
519	            sdcparse::CreateClock new_create_clock_cmd;
520	            new_create_clock_cmd.add = false;
521	            new_create_clock_cmd.is_virtual = false;
522	            new_create_clock_cmd.name = clock_name;
523	            new_create_clock_cmd.targets = cmd.targets;
524	            new_create_clock_cmd.period = generated_clock_period;
525	            new_create_clock_cmd.rise_edge = generated_rise_edge;
526	            new_create_clock_cmd.fall_edge = generated_fall_edge;
527	
528	            // Create the netlist clock (a clock net which ultimately drives a
529	            // clock pin on some block in the design netlist).
530	            create_clock_object(clock_name, clock_source, new_create_clock_cmd);
531	        }
532	    }
