534	    void set_io_delay(const sdcparse::SetIoDelay& cmd) override {
535	        num_commands_++;
536	
537	        if (cmd.associated_clocks.empty()) {
538	            // TODO: This should be relaxed.
539	            vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
540	                      "set_io_delay currently requires the clock to be specified");
541	        }
542	
543	        bool clocks_valid = check_objects(cmd.associated_clocks,
544	                                          {sdcparse::ObjectType::Clock});
545	        if (!clocks_valid) {
546	            vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
547	                      "set_io_delay command only supports clock objects for -clock");
548	        }
549	
550	        //Error checks
551	        std::set<tatum::DomainId> domains = get_clocks(cmd.associated_clocks);
552	        if (domains.empty()) {
553	            vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
554	                      "Failed to find clock domain for I/O constraint");
555	        }
556	
557	        // Verify that the targets are the correct type.
558	        // TODO: We may be able to support pins as well. Need to verify.
559	        bool targets_valid = check_objects(cmd.target_ports,
560	                                           {sdcparse::ObjectType::Port});
561	        if (!targets_valid) {
562	            vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
563	                      "set_io_delay command only supports ports currently");
564	        }
565	
566	        // Get the target ports
567	        std::set<AtomPinId> io_pins = get_ports(cmd.target_ports);
568	
569	        if (io_pins.empty()) {
570	            //We treat this as a warning, since the primary I/Os in the target may have been swept away
571	            VTR_LOGF_WARN(fname_.c_str(), lineno_,
572	                          "Found no matching primary inputs or primary outputs for %s\n",
573	                          (cmd.type == sdcparse::IoDelayType::INPUT) ? "set_input_delay" : "set_output_delay");
574	        }
575	
576	        bool is_max = cmd.is_max;
577	        bool is_min = cmd.is_min;
578	        if (!is_max && !is_min) {
579	            //Unspecified implies both
580	            is_max = true;
581	            is_min = true;
582	        }
583	
584	        float delay = sdc_units_to_seconds(cmd.delay);
585	
586	        for (AtomPinId pin : io_pins) {
587	            tatum::NodeId tnode = lookup_.atom_pin_tnode(pin);
588	            VTR_ASSERT(tnode);
589	
590	            //Set i/o constraint
591	            if (cmd.type == sdcparse::IoDelayType::INPUT) {
592	                if (netlist_.pin_type(pin) == PinType::DRIVER) {
593	                    for (tatum::DomainId domain : domains) {
594	                        if (is_max) {
595	                            tc_.set_input_constraint(tnode, domain, tatum::DelayType::MAX, tatum::Time(delay));
596	                        }
597	                        if (is_min) {
598	                            tc_.set_input_constraint(tnode, domain, tatum::DelayType::MIN, tatum::Time(delay));
599	                        }
600	                    }
601	                } else {
602	                    VTR_ASSERT(netlist_.pin_type(pin) == PinType::SINK);
603	
604	                    AtomBlockId blk = netlist_.pin_block(pin);
605	                    std::string io_name = orig_blif_name(netlist_.block_name(blk));
606	
607	                    VTR_LOGF_WARN(fname_.c_str(), lineno_,
608	                                  "set_input_delay command matched but was not applied to primary output '%s'\n",
609	                                  io_name.c_str());
610	                }
611	            } else {
612	                VTR_ASSERT(cmd.type == sdcparse::IoDelayType::OUTPUT);
613	
614	                if (netlist_.pin_type(pin) == PinType::SINK) {
615	                    for (tatum::DomainId domain : domains) {
616	                        if (is_max) {
617	                            tc_.set_output_constraint(tnode, domain, tatum::DelayType::MAX, tatum::Time(delay));
618	                        }
619	                        if (is_min) {
620	                            tc_.set_output_constraint(tnode, domain, tatum::DelayType::MIN, tatum::Time(delay));
621	                        }
622	                    }
623	                } else {
624	                    VTR_ASSERT(netlist_.pin_type(pin) == PinType::DRIVER);
625	                    AtomBlockId blk = netlist_.pin_block(pin);
626	                    std::string io_name = orig_blif_name(netlist_.block_name(blk));
627	
628	                    VTR_LOGF_WARN(fname_.c_str(), lineno_,
629	                                  "set_output_delay command matched but was not applied to primary input '%s'\n",
630	                                  io_name.c_str());
631	                }
632	            }
633	        }
634	    }
