636	    void set_clock_groups(const sdcparse::SetClockGroups& cmd) override {
637	        num_commands_++;
638	
639	        // The three clock-group relationship types differ in how they affect SI/crosstalk
640	        // analysis, but are identical from a pure timing (STA) standpoint; in all three
641	        // cases, no setup/hold paths are analyzed between clocks in different groups:
642	        //
643	        //   -physically_exclusive: only one clock can exist in the design at a time
644	        //       (e.g. a board-level mux selects among several clock sources). Neither
645	        //       STA nor SI is performed between the groups.
646	        //
647	        //   -logically_exclusive: an internal mux selects among the clocks, so paths
648	        //       between groups are false paths. Both clock trees are physically present
649	        //       simultaneously, so SI/crosstalk between the groups is still possible.
650	        //
651	        //   -asynchronous: all clocks coexist and propagate through the design but have
652	        //       no defined phase relationship. Paths between groups are not timed, but
653	        //       SI/crosstalk is still possible.
654	        //
655	        // VPR does not model SI/crosstalk, so all three types are implemented identically:
656	        // timing analysis is disabled between every pair of clocks in different groups.
657	        if (cmd.type != sdcparse::ClockGroupsType::ASYNCHRONOUS
658	            && cmd.type != sdcparse::ClockGroupsType::PHYSICALLY_EXCLUSIVE
659	            && cmd.type != sdcparse::ClockGroupsType::LOGICALLY_EXCLUSIVE) {
660	            vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
661	                      "set_clock_groups only supports -asynchronous, -physically_exclusive, and -logically_exclusive groups");
662	        }
663	
664	        for (const auto& clock_group : cmd.clock_groups) {
665	            bool clock_group_valid = check_objects(clock_group,
666	                                                   {sdcparse::ObjectType::Clock});
667	            if (!clock_group_valid) {
668	                vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
669	                          "set_clock_groups only supports clock targets");
670	            }
671	        }
672	
673	        //FIXME: more efficient to collect per-group clocks once instead of at each iteration
674	
675	        //Disable timing between each group of clock domains
676	        for (size_t src_group = 0; src_group < cmd.clock_groups.size(); ++src_group) {
677	            auto src_clocks = get_clocks(cmd.clock_groups[src_group]);
678	
679	            for (size_t sink_group = 0; sink_group < cmd.clock_groups.size(); ++sink_group) {
680	                if (src_group == sink_group) continue;
681	
682	                auto sink_clocks = get_clocks(cmd.clock_groups[sink_group]);
683	
684	                for (auto src_clock : src_clocks) {
685	                    for (auto sink_clock : sink_clocks) {
686	                        //Mark this pair of domains to be disabled
687	                        disabled_domain_pairs_.insert({src_clock, sink_clock});
688	                    }
689	                }
690	            }
691	        }
692	    }
