694	    void set_false_path(const sdcparse::SetFalsePath& cmd) override {
695	        num_commands_++;
696	
697	        bool from_targets_valid = check_objects(cmd.from,
698	                                                {sdcparse::ObjectType::Clock});
699	        bool to_targets_valid = check_objects(cmd.to,
700	                                              {sdcparse::ObjectType::Clock});
701	        if (!(from_targets_valid && to_targets_valid)) {
702	            vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
703	                      "set_false_path: False paths are currently only supported between entire clock domains");
704	        }
705	
706	        auto from_clocks = get_clocks(cmd.from);
707	        auto to_clocks = get_clocks(cmd.to);
708	
709	        if (from_clocks.empty() && to_clocks.empty()) {
710	            vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
