937	    void set_disable_timing(const sdcparse::SetDisableTiming& cmd) override {
938	        num_commands_++;
939	
940	        bool from_targets_valid = check_objects(cmd.from,
941	                                                {sdcparse::ObjectType::Pin});
942	        bool to_targets_valid = check_objects(cmd.to,
943	                                              {sdcparse::ObjectType::Pin});
944	        if (!(from_targets_valid && to_targets_valid)) {
945	            vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
946	                      "set_disable_timing only supported between pins");
947	        }
948	
949	        //Collect the specified pins
950	        auto from_pins = get_pins(cmd.from);
951	        auto to_pins = get_pins(cmd.to);
952	
953	        if (from_pins.empty()) {
954	            vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
955	                      "Found no matching -from pins");
956	        }
957	
958	        if (to_pins.empty()) {
959	            vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
960	                      "Found no matching -to pins");
961	        }
962	
963	        //Disable any edges between the from and to sets
964	        for (auto from_pin : from_pins) {
965	            for (auto to_pin : to_pins) {
966	                tatum::NodeId from_tnode = lookup_.atom_pin_tnode(from_pin);
967	                VTR_ASSERT(from_tnode);
968	
969	                tatum::NodeId to_tnode = lookup_.atom_pin_tnode(to_pin);
970	                VTR_ASSERT(to_tnode);
971	
972	                //Find the edge matching these nodes
973	                tatum::EdgeId edge = tg_.find_edge(from_tnode, to_tnode);
974	
975	                if (!edge) {
976	                    const auto& from_pin_name = netlist_.pin_name(from_pin);
977	                    const auto& to_pin_name = netlist_.pin_name(to_pin);
978	
979	                    VTR_LOGF_WARN(fname_.c_str(), lineno_,
980	                                  "set_disable_timing no timing edge found from pin '%s' to pin '%s'\n",
981	                                  from_pin_name.c_str(), to_pin_name.c_str());
982	                }
983	
984	                //Mark the edge in the timing graph as disabled
985	                tg_.disable_edge(edge);
986	
987	                //If we have disabled all incoming edges of the to_tnode we need to mark
988	                //it as a constant generator to avoid causing errors during timing analysis
989	                //(since the node will appear in the first level of the timing graph but is not
990	                //a primary input).
991	                if (tg_.node_num_active_in_edges(to_tnode) == 0) {
992	                    VTR_LOGF_WARN(fname_.c_str(), lineno_,
993	                                  "set_disable_timing caused pin '%s' to have no active incoming edges. It is being marked as a constant generator.\n",
994	                                  netlist_.pin_name(to_pin).c_str());
995	                    tc_.set_constant_generator(to_tnode);
996	                }
997	            }
998	        }
999	    }
