1041	    void resolve_clock_constraints() {
1042	        //Set the clock constraints
1043	        for (tatum::DomainId launch_clock : tc_.clock_domains()) {
1044	            for (tatum::DomainId capture_clock : tc_.clock_domains()) {
1045	                auto domain_pair = std::make_pair(launch_clock, capture_clock);
1046	
1047	                if (disabled_domain_pairs_.count(domain_pair)) continue;
1048	
1049	                //Setup -- default
1050	                {
1051	                    tatum::Time setup_constraint = calculate_setup_constraint(launch_clock, capture_clock);
1052	                    VTR_ASSERT(setup_constraint.valid());
1053	
1054	                    tc_.set_setup_constraint(launch_clock, capture_clock, setup_constraint);
1055	                }
1056	
1057	                //Setup -- capture pin overrides
1058	                for (auto pin : setup_capture_pins_with_overrides()) {
1059	                    tatum::Time setup_constraint = calculate_setup_constraint(launch_clock, capture_clock, pin);
1060	                    VTR_ASSERT(setup_constraint.valid());
1061	
1062	                    tatum::NodeId tnode = lookup_.atom_pin_tnode(pin);
1063	                    VTR_ASSERT(tnode);
1064	
1065	                    tc_.set_setup_constraint(launch_clock, capture_clock, tnode, setup_constraint);
1066	                }
1067	
1068	                //Hold -- default
1069	                {
1070	                    tatum::Time hold_constraint = calculate_hold_constraint(launch_clock, capture_clock);
1071	                    VTR_ASSERT(hold_constraint.valid());
1072	
1073	                    tc_.set_hold_constraint(launch_clock, capture_clock, hold_constraint);
1074	                }
1075	
1076	                //Setup -- capture pin overrides
1077	                for (auto pin : hold_capture_pins_with_overrides()) {
1078	                    tatum::Time hold_constraint = calculate_hold_constraint(launch_clock, capture_clock, pin);
1079	                    VTR_ASSERT(hold_constraint.valid());
1080	
1081	                    tatum::NodeId tnode = lookup_.atom_pin_tnode(pin);
1082	                    VTR_ASSERT(tnode);
1083	
1084	                    tc_.set_hold_constraint(launch_clock, capture_clock, tnode, hold_constraint);
1085	                }
1086	            }
1087	        }
1088	    }
1089	
1090	    //Returns the setup constraint in seconds
1091	    tatum::Time calculate_setup_constraint(tatum::DomainId launch_domain, tatum::DomainId capture_domain, AtomPinId to_pin = AtomPinId::INVALID()) const {
1092	        //Calculate the period-based constraint, including the effect of multi-cycle paths
1093	        float min_launch_to_capture_time = calculate_launch_to_capture_edge_times(launch_domain, capture_domain).setup;
1094	
1095	        auto iter = sdc_clocks_.find(capture_domain);
1096	        VTR_ASSERT(iter != sdc_clocks_.end());
1097	        float capture_period = iter->second.period;
1098	
1099	        // The period-based setup constraint is the base setup edge time plus extra capture cycles.
1100	        //
1101	        // .setup is already the minimum time to the first capture edge after any launch edge, so it
1102	        // implicitly represents one capture cycle. extra_cycles is therefore (setup_mcp - 1): the
1103	        // default setup_mcp of 1 adds zero extra cycles, while a 2-cycle MCP adds one full period.
1104	        int extra_cycles = setup_capture_cycle(launch_domain, capture_domain, to_pin) - 1;
1105	        float period_based_setup_constraint = min_launch_to_capture_time + capture_period * extra_cycles;
1106	
1107	        //Warn the user if we added negative cycles
1108	        if (extra_cycles < 0) {
1109	            VTR_LOG_WARN(
1110	                "Added negative (%d) additional capture clock cycles to setup constraint"
1111	                " for clock '%s' to clock '%s' transfers; check your set_multicycle_path specifications\n",
1112	                extra_cycles, tc_.clock_domain_name(launch_domain).c_str(), tc_.clock_domain_name(capture_domain).c_str());
1113	        }
1114	
1115	        //By default the period-based constraint is the constraint
1116	        float setup_constraint = period_based_setup_constraint;
1117	
1118	        //See if we have any other override constraints
1119	        auto domain_pair = std::make_pair(launch_domain, capture_domain);
1120	        auto override_iter = setup_override_constraints_.find(domain_pair);
1121	        if (override_iter != setup_override_constraints_.end()) {
1122	            float override_setup_constraint = override_iter->second;
1123	
1124	            if (setup_constraint > override_setup_constraint) {
1125	                VTR_LOG_WARN(
1126	                    "Override setup constraint (%g) overrides a tighter default period-based constraint (%g)"
1127	                    " for transfers from clock '%s' to clock '%s'\n",
1128	                    override_setup_constraint, setup_constraint,
1129	                    tc_.clock_domain_name(launch_domain).c_str(),
1130	                    tc_.clock_domain_name(capture_domain).c_str());
1131	            }
1132	
1133	            //Override the constraint
1134	            setup_constraint = override_setup_constraint;
1135	        }
1136	
1137	        setup_constraint = sdc_units_to_seconds(setup_constraint);
1138	
1139	        if (setup_constraint < 0.) {
1140	            VPR_ERROR(VPR_ERROR_SDC,
1141	                      "Setup constraint %g for transfers from clock '%s' to clock '%s' is negative."
1142	                      " Requires data to arrive before launch edge (No time travelling allowed!)",
1143	                      setup_constraint,
1144	                      tc_.clock_domain_name(launch_domain).c_str(),
1145	                      tc_.clock_domain_name(capture_domain).c_str());
1146	        }
1147	
1148	        return tatum::Time(setup_constraint);
1149	    }
1150	
1151	    //Returns the hold constraint in seconds
1152	    tatum::Time calculate_hold_constraint(tatum::DomainId launch_domain, tatum::DomainId capture_domain, AtomPinId to_pin = AtomPinId::INVALID()) const {
1153	        // .hold is the maximum (hold_capture_edge - launch_edge) across all launch edges, where
1154	        // hold_capture_edge is one capture period before the nearest setup capture edge for each
1155	        // launch edge. See calculate_launch_to_capture_edge_times for the full algorithm.
1156	        float max_hold_launch_to_capture_time = calculate_launch_to_capture_edge_times(launch_domain, capture_domain).hold;
1157	
1158	        auto iter = sdc_clocks_.find(capture_domain);
1159	        VTR_ASSERT(iter != sdc_clocks_.end());
1160	        float capture_period = iter->second.period;
1161	
1162	        // The period-based hold constraint is the base hold edge time adjusted for MCP.
1163	        // hold_capture_cycle is 0 by default (use the default hold edge), and increases for
1164	        // multi-cycle paths — e.g. hold_capture_cycle=1 when setup MCP is 2.
1165	        int hold_cycle = hold_capture_cycle(launch_domain, capture_domain, to_pin);
1166	        float period_based_hold_constraint = max_hold_launch_to_capture_time + capture_period * hold_cycle;
1167	
1168	        //By default the period-based constraint is the constraint
1169	        float hold_constraint = period_based_hold_constraint;
1170	
1171	        //See if we have any other override constraints
1172	        auto domain_pair = std::make_pair(launch_domain, capture_domain);
1173	        auto override_iter = hold_override_constraints_.find(domain_pair);
1174	        if (override_iter != hold_override_constraints_.end()) {
1175	            float override_hold_constraint = override_iter->second;
1176	
1177	            if (hold_constraint < override_hold_constraint) {
1178	                VTR_LOG_WARN(
1179	                    "Override hold constraint (%g) overrides tighter default period-based constraint (%g)"
1180	                    " for transfers from clock '%s' to clock '%s'\n",
1181	                    override_hold_constraint, hold_constraint,
1182	                    tc_.clock_domain_name(launch_domain).c_str(),
1183	                    tc_.clock_domain_name(capture_domain).c_str());
1184	            }
1185	
1186	            //Override the constraint
1187	            hold_constraint = override_hold_constraint;
1188	        }
1189	
1190	        hold_constraint = sdc_units_to_seconds(hold_constraint);
1191	
1192	        return tatum::Time(hold_constraint);
1193	    }
1194	
1195	    //Return type for calculate_launch_to_capture_edge_times.
1196	    struct LaunchCaptureEdgeTimes {
1197	        float setup; //Min strictly-positive (capture_edge - launch_edge) across all pairs
1198	        float hold;  //Max (hold_capture_edge - launch_edge) across all launch edges, where
1199	                     //hold_capture_edge is one capture period before the nearest capture after each launch
1200	    };
1201	
1202	    //Determine the period-based setup and hold edge times (in SDC units) between the
1203	    //edges of the launch and capture clocks, returning both in a single pass.
1204	    //
1205	    // The edge arrays span one LCM window so the full repeating pattern is covered.
1206	    // For each launch edge, the nearest capture edge strictly after it is found by
1207	    // scanning the sorted capture_edges array and breaking at the first match.
1208	    //
1209	    // Setup (.setup): the minimum (capture_edge - launch_edge) across all launch edges.
1210	    // One global minimum suffices; the nearest capture edge per launch edge is already the
1211	    // smallest possible diff for that launch edge.
1212	    //
1213	    // Hold (.hold): the maximum (capture_edge - capture_period - launch_edge) across all
1214	    // launch edges, where (capture_edge - capture_period) is the hold capture edge — one
1215	    // period before the nearest setup capture. A per-launch-edge maximum is required because
1216	    // the tightest setup pair is not necessarily the tightest hold pair for phase-related or
1217	    // differently-periodic clocks.
1218	    //
1219	    // Example: launch period=6ns (rise 0ns), capture period=12ns (rise 0ns):
1220	    //   Launch=0ns -> nearest cap=12ns -> hold cap=0ns  -> setup=12ns, hold= 0ns
1221	    //   Launch=6ns -> nearest cap=12ns -> hold cap=0ns  -> setup= 6ns, hold=-6ns
1222	    //   Result: setup=min(12,6)=6ns,  hold=max(0,-6)=0ns.
1223	    LaunchCaptureEdgeTimes calculate_launch_to_capture_edge_times(tatum::DomainId launch_domain, tatum::DomainId capture_domain) const {
1224	        constexpr int CLOCK_SCALE = 1000;
1225	
1226	        auto launch_iter = sdc_clocks_.find(launch_domain);
1227	        VTR_ASSERT(launch_iter != sdc_clocks_.end());
1228	        const sdcparse::CreateClock& launch_clock = launch_iter->second;
1229	
1230	        auto capture_iter = sdc_clocks_.find(capture_domain);
1231	        VTR_ASSERT(capture_iter != sdc_clocks_.end());
1232	        const sdcparse::CreateClock& capture_clock = capture_iter->second;
1233	
1234	        VTR_ASSERT_MSG(launch_clock.period >= 0., "Clock period must be positive");
1235	        VTR_ASSERT_MSG(capture_clock.period >= 0., "Clock period must be positive");
1236	
1237	        if (vtr::isclose(launch_clock.period, capture_clock.period)
1238	            && vtr::isclose(launch_clock.rise_edge, capture_clock.rise_edge)
1239	            && vtr::isclose(launch_clock.fall_edge, capture_clock.fall_edge)) {
1240	            //The source and sink domains have the same period and edges.
1241	            //The setup constraint is the common clock period; the hold constraint is 0.
1242	            return {float(launch_clock.period), 0.f};
1243	        } else if (vtr::isclose(launch_clock.period, 0.0) || vtr::isclose(capture_clock.period, 0.0)) {
1244	            //If either period is 0, the constraint is 0
1245	            return {0.f, 0.f};
1246	        } else {
1247	            //Multiply periods and edges by CLOCK_SCALE and round down to the nearest
1248	            //integer, to avoid messy decimals.
1249	            int launch_period = static_cast<int>(launch_clock.period * CLOCK_SCALE);
1250	            int capture_period = static_cast<int>(capture_clock.period * CLOCK_SCALE);
1251	            int launch_rise_edge = static_cast<int>(launch_clock.rise_edge * CLOCK_SCALE);
1252	            int capture_rise_edge = static_cast<int>(capture_clock.rise_edge * CLOCK_SCALE);
1253	
1254	            // Normalize rise edges to [0, period) to handle values the SDC parser may
1255	            // produce outside that range (e.g. from generated clocks with large phases).
1256	            // In practice rise edges should always be non-negative, but the double-modulo
1257	            // pattern ((x % n) + n) % n handles negative values safely just in case.
1258	            launch_rise_edge = ((launch_rise_edge % launch_period) + launch_period) % launch_period;
1259	            capture_rise_edge = ((capture_rise_edge % capture_period) + capture_period) % capture_period;
1260	
1261	            //Find the LCM of the two periods. This determines how long it takes before
1262	            //the pattern of the two clocks' edges starts repeating.
1263	            int lcm_period = vtr::lcm(launch_period, capture_period);
1264	
1265	            //Create arrays of edges for each clock over one LCM period.
1266	
1267	            //Launch edges (+1 extra to handle boundary launch edges).
1268	            std::vector<int> launch_edges;
1269	            int launch_rise_time = launch_rise_edge;
1270	            int num_launch_edges = lcm_period / launch_period + 1;
1271	            for (int i = 0; i < num_launch_edges; ++i) {
1272	                launch_edges.push_back(launch_rise_time);
1273	                launch_rise_time += launch_period;
1274	            }
1275	
1276	            //Capture edges (+2 extra to guarantee every launch edge in the window has at
1277	            //least one capture edge strictly after it; e.g. a launch at the last edge of
1278	            //the LCM window needs a capture edge one full capture period beyond it).
1279	            std::vector<int> capture_edges;
1280	            int capture_rise_time = capture_rise_edge;
1281	            int num_capture_edges = lcm_period / capture_period + 2;
1282	            for (int i = 0; i < num_capture_edges; ++i) {
1283	                capture_edges.push_back(capture_rise_time);
1284	                capture_rise_time += capture_period;
1285	            }
1286	
1287	            //For each launch edge, find the nearest capture edge strictly after it.
1288	            //Since capture_edges is sorted, the first capture_edge > launch_edge is the nearest,
1289	            //so we break after finding it. That single nearest pair contributes:
1290	            //  - the minimum setup diff (capture_edge - launch_edge), and
1291	            //  - the hold diff for this launch edge (capture_edge - capture_period - launch_edge).
1292	            int scaled_setup = std::numeric_limits<int>::max();
1293	            int scaled_hold = std::numeric_limits<int>::min();
1294	
1295	            for (int launch_edge : launch_edges) {
1296	                for (int capture_edge : capture_edges) {
1297	                    if (capture_edge > launch_edge) {
1298	                        scaled_setup = std::min(scaled_setup, capture_edge - launch_edge);
1299	                        scaled_hold = std::max(scaled_hold, capture_edge - capture_period - launch_edge);
1300	                        // Break from inner loop only: min/max accumulate across launch edges in the outer loop
1301	                        break;
1302	                    }
1303	                }
1304	            }
1305	
1306	            VTR_ASSERT(scaled_setup != std::numeric_limits<int>::max());
1307	            VTR_ASSERT(scaled_hold != std::numeric_limits<int>::min());
1308	
1309	            return {float(scaled_setup) / CLOCK_SCALE, float(scaled_hold) / CLOCK_SCALE};
1310	        }
1311	    }
