1313	    //Returns the cycle number (after launch) where the setup check occurs
1314	    int setup_capture_cycle(tatum::DomainId from, tatum::DomainId to, AtomPinId to_pin = AtomPinId::INVALID()) const {
1315	        //The setup capture cycle is the setup mcp value
1316	
1317	        //Any domain pair + pin-specific (possibly wildcard) override
1318	        auto key = std::make_tuple(from, to, to_pin);
1319	        auto iter = setup_mcp_overrides_.find(key);
1320	        if (iter != setup_mcp_overrides_.end()) {
1321	            return iter->second;
1322	        }
1323	
1324	        //Pin-specific override not found, look for Domain pair overrides
1325	        key = std::make_tuple(from, to, AtomPinId::INVALID());
1326	        iter = setup_mcp_overrides_.find(key);
1327	        if (iter != setup_mcp_overrides_.end()) {
1328	            return iter->second;
1329	        }
1330	
1331	        //Default: capture one cycle after launch
1332	        return 1;
1333	    }
1334	
1335	    //Returns the cycle number (after launch) where the hold check occurs
1336	    int hold_capture_cycle(tatum::DomainId from, tatum::DomainId to, AtomPinId to_pin = AtomPinId::INVALID()) const {
1337	        //Default: hold captures the cycle before setup is captured
1338	        //For the default setup mcp this implies capturing the same
1339	        //cycle as launch
1340	        int hold_offset = 1;
1341	
1342	        //Any domain pair + pin-specific (possibly wildcard) override
1343	        auto key = std::make_tuple(from, to, to_pin);
1344	        auto iter = hold_mcp_overrides_.find(key);
1345	        if (iter != hold_mcp_overrides_.end()) {
1346	            //Note that we add the override to the default hold_mcp of 1 to match
1347	            //the standard SDC behaviour (e.g. N - 1) of hold multicycles.
1348	            //
1349	            //For details see section 8.3 'Multicycle paths' in:
1350	            //  J. Bhasker, R. Chadha, "Static Timing Analysis for Nanometer
1351	            //      Designs A Practical Approach", Springer, 2009
1352	            hold_offset += iter->second;
1353	        } else {
1354	            //Pin-specific override not found, look for Domain pair overrides
1355	            key = std::make_tuple(from, to, AtomPinId::INVALID());
1356	            iter = hold_mcp_overrides_.find(key);
1357	            if (iter != hold_mcp_overrides_.end()) {
1358	                hold_offset += iter->second;
1359	            }
1360	        }
1361	
1362	        //The hold capture cycle is the setup capture cycle minus the hold mcp value
1363	        return setup_capture_cycle(from, to, to_pin) - hold_offset;
1364	    }
