1406	        // Ensure that the pin is a driver of a clock. This may be necessary for setting
1407	        // the source of the clock.
1408	        if (netlist_clock_drivers_.count(clock_pin) != 1) {
1409	            std::string pin_name = netlist_.pin_name(clock_pin);
1410	            vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
1411	                      "Pin '%s' is not a valid clock source. Clock pins currently must drive a clock net.",
1412	                      pin_name.c_str());
1413	        }
1414	
1415	        // Get the clock source
1416	        AtomNetId clock_net = netlist_.pin_net(clock_pin);
1417	        AtomPinId clock_driver = netlist_.net_driver(clock_net);
1418	        tatum::NodeId clock_source = lookup_.atom_pin_tnode(clock_driver);
1419	        VTR_ASSERT(clock_source);
1420	
1421	        return clock_source;
