1424	    /**
1425	     * @brief Get the clock target pins referred to by the given objects.
1426	     *
1427	     * This is used by the clock creating SDC commands to get the driver pins of the
1428	     * netlist clocks. This allows us to unify the code such that the target objects
1429	     * can be pins, ports, and/or nets and naturally dedupe them.
1430	     *
1431	     * NOTE: This method returns a pair of pins and their names. The reason is that the
1432	     *       object contains the name information. Once the objects are parsed into pins,
1433	     *       this information gets lost, but it is still needed. In the case of dupes, the
1434	     *       first object found is chosen as the name (which matches other SDC
1435	     *       implementations).
1436	     *
1437	     *  @param target_objects   List of objects to get the clock target pins of.
1438	     *
1439	     *  @return A map containing the set of clock target pins and their names.
1440	     */
1441	    std::map<AtomPinId, std::string> get_clock_target_pins(const std::vector<sdcparse::ObjectId>& target_objects) {
1442	        std::map<AtomPinId, std::string> target_pins;
1443	        for (sdcparse::ObjectId object_id : target_objects) {
1444	            sdcparse::ObjectType object_type = obj_database.get_object_type(object_id);
1445	            AtomPinId clock_pin;
1446	            if (object_type == sdcparse::ObjectType::Port || object_type == sdcparse::ObjectType::Pin) {
1447	                // When the target of the create_clock command is a pin, we implicitly are targeting
1448	                // the driver of the net that this pin is a part of (i.e. the whole clock net).
1449	                AtomPinId target_pin = get_port_or_pin(object_id);
1450	                VTR_ASSERT(target_pin.is_valid());
1451	                AtomNetId target_net = netlist_.pin_net(target_pin);
1452	                clock_pin = netlist_.net_driver(target_net);
1453	            } else {
1454	                VTR_ASSERT(object_type == sdcparse::ObjectType::Net);
1455	                // When the target of the create_clock command is a net, we implicitly are targeting
1456	                // the driver of that net.
1457	                AtomNetId target_net = get_net(object_id);
1458	                VTR_ASSERT(target_net.is_valid());
1459	                clock_pin = netlist_.net_driver(target_net);
1460	                if (!clock_pin.is_valid()) {
1461	                    std::string net_name = netlist_.net_name(target_net);
1462	                    vpr_throw(VPR_ERROR_SDC, fname_.c_str(), lineno_,
1463	                              "Net '%s' has no driver and cannot be used as a clock target",
1464	                              net_name.c_str());
1465	                }
1466	            }
1467	            VTR_ASSERT(clock_pin.is_valid());
1468	
1469	            if (!target_pins.contains(clock_pin)) {
1470	                std::string object_name = obj_database.get_object_name(sdcparse::ObjectId(object_id));
1471	                target_pins.insert(std::make_pair(clock_pin, object_name));
1472	            }
1473	        }
1474	
1475	        return target_pins;
1476	    }
