1661	std::unique_ptr<tatum::TimingConstraints> read_sdc(const t_timing_inf& timing_inf,
1662	                                                   const AtomNetlist& netlist,
1663	                                                   const AtomLookup& lookup,
1664	                                                   const LogicalModels& models,
1665	                                                   tatum::TimingGraph& timing_graph) {
1666	    auto timing_constraints = std::make_unique<tatum::TimingConstraints>();
1667	
1668	    if (!timing_inf.timing_analysis_enabled) {
1669	        VTR_LOG("\n");
1670	        VTR_LOG("Timing analysis off\n");
1671	        apply_default_timing_constraints(netlist, lookup, models, *timing_constraints);
1672	    } else {
1673	        if (!std::filesystem::exists(timing_inf.SDCFile)) {
1674	            //No SDC file
1675	            VTR_LOG("\n");
1676	            VTR_LOG("SDC file '%s' not found\n", timing_inf.SDCFile.c_str());
1677	            apply_default_timing_constraints(netlist, lookup, models, *timing_constraints);
1678	        } else {
1679	            //Parse the file
1680	            SdcParseCallback callback(netlist, lookup, models, *timing_constraints, timing_graph);
1681	            sdcparse::sdc_parse_filename(timing_inf.SDCFile.c_str(), callback);
1682	
1683	            if (callback.num_commands() == 0) {
1684	                VTR_LOG("\n");
1685	                VTR_LOG("SDC file '%s' contained no SDC commands\n", timing_inf.SDCFile.c_str());
1686	                apply_default_timing_constraints(netlist, lookup, models, *timing_constraints);
1687	            } else {
1688	                VTR_LOG("\n");
1689	                VTR_LOG("Applied %zu SDC commands from '%s'\n", callback.num_commands(), timing_inf.SDCFile.c_str());
1690	            }
1691	        }
1692	    }
1693	    VTR_LOG("Timing constraints created %zu clocks\n", timing_constraints->clock_domains().size());
1694	    for (tatum::DomainId domain : timing_constraints->clock_domains()) {
1695	        if (timing_constraints->is_virtual_clock(domain)) {
1696	            VTR_LOG("  Constrained Clock '%s' (Virtual Clock)\n",
1697	                    timing_constraints->clock_domain_name(domain).c_str());
1698	        } else {
1699	            tatum::NodeId src_tnode = timing_constraints->clock_domain_source_node(domain);
1700	            VTR_ASSERT(src_tnode);
1701	
1702	            AtomPinId src_pin = lookup.tnode_atom_pin(src_tnode);
1703	            VTR_ASSERT(src_pin);
1704	
1705	            VTR_LOG("  Constrained Clock '%s' Source: '%s'\n",
1706	                    timing_constraints->clock_domain_name(domain).c_str(),
1707	                    netlist.pin_name(src_pin).c_str());
1708	        }
1709	    }
1710	
1711	    VTR_LOG("\n");
1712	
1713	    return timing_constraints;
1714	}
1715	
1716	//Apply the default timing constraints (i.e. if there are no user specified constraints)
1717	//appropriate to the type of circuit.
1718	void apply_default_timing_constraints(const AtomNetlist& netlist,
1719	                                      const AtomLookup& lookup,
1720	                                      const LogicalModels& models,
1721	                                      tatum::TimingConstraints& tc) {
1722	    std::set<AtomPinId> netlist_clock_drivers = find_netlist_logical_clock_drivers(netlist, models);
1723	
1724	    if (netlist_clock_drivers.size() == 0) {
1725	        apply_combinational_default_timing_constraints(netlist, lookup, tc);
1726	
1727	    } else if (netlist_clock_drivers.size() == 1) {
1728	        apply_single_clock_default_timing_constraints(netlist, lookup, *netlist_clock_drivers.begin(), tc);
1729	
1730	    } else {
1731	        VTR_ASSERT(netlist_clock_drivers.size() > 1);
1732	
1733	        apply_multi_clock_default_timing_constraints(netlist, lookup, netlist_clock_drivers, tc);
1734	    }
1735	}
1736	
1737	//Apply the default timing constraints for purely combinational circuits which have
1738	//no explicit netlist clock
1739	void apply_combinational_default_timing_constraints(const AtomNetlist& netlist,
1740	                                                    const AtomLookup& lookup,
1741	                                                    tatum::TimingConstraints& tc) {
1742	    std::string clock_name = "virtual_io_clock";
1743	
1744	    VTR_LOG("Setting default timing constraints:\n");
1745	    VTR_LOG("   * constrain all primary inputs and primary outputs on a virtual external clock '%s'\n", clock_name.c_str());
1746	    VTR_LOG("   * optimize virtual clock to run as fast as possible\n");
1747	
1748	    //Create a virtual clock, with 0 period
1749	    tatum::DomainId domain = tc.create_clock_domain(clock_name);
1750	    tc.set_setup_constraint(domain, domain, tatum::Time(0.));
1751	    tc.set_hold_constraint(domain, domain, tatum::Time(0.));
1752	
1753	    //Constrain all I/Os with zero input/output delay
1754	    constrain_all_ios(netlist, lookup, tc, domain, domain, tatum::Time(0.), tatum::Time(0.));
1755	
1756	    //Mark constant generator timing nodes
1757	    mark_constant_generators(netlist, lookup, tc);
1758	}
1759	
1760	//Apply the default timing constraints for circuits with a single netlist clock
1761	void apply_single_clock_default_timing_constraints(const AtomNetlist& netlist,
1762	                                                   const AtomLookup& lookup,
1763	                                                   const AtomPinId clock_driver,
1764	                                                   tatum::TimingConstraints& tc) {
1765	    AtomNetId clock_net = netlist.pin_net(clock_driver);
1766	    std::string clock_name = netlist.net_name(clock_net);
1767	
1768	    VTR_LOG("Setting default timing constraints:\n");
1769	    VTR_LOG("   * constrain all primary inputs and primary outputs on netlist clock '%s'\n", clock_name.c_str());
1770	    VTR_LOG("   * optimize netlist clock to run as fast as possible\n");
1771	
1772	    //Create the netlist clock with period 0
1773	    tatum::DomainId domain = tc.create_clock_domain(clock_name);
1774	    tc.set_setup_constraint(domain, domain, tatum::Time(0.));
1775	    tc.set_hold_constraint(domain, domain, tatum::Time(0.));
1776	
1777	    //Mark the clock domain source
1778	    AtomPinId clock_driver_pin = netlist.net_driver(clock_net);
1779	    tatum::NodeId clock_source = lookup.atom_pin_tnode(clock_driver_pin);
1780	    VTR_ASSERT(clock_source);
1781	    tc.set_clock_domain_source(clock_source, domain);
1782	
1783	    //Constrain all I/Os with zero input/output delay
1784	    constrain_all_ios(netlist, lookup, tc, domain, domain, tatum::Time(0.), tatum::Time(0.));
1785	
1786	    //Mark constant generator timing nodes
1787	    mark_constant_generators(netlist, lookup, tc);
1788	}
1789	
1790	//Apply the default timing constraints for circuits with multiple netlist clocks
1791	void apply_multi_clock_default_timing_constraints(const AtomNetlist& netlist,
1792	                                                  const AtomLookup& lookup,
1793	                                                  const std::set<AtomPinId>& clock_drivers,
1794	                                                  tatum::TimingConstraints& tc) {
1795	    std::string virtual_clock_name = "virtual_io_clock";
1796	    VTR_LOG("Setting default timing constraints:\n");
1797	    VTR_LOG("   * constrain all primary inputs and primary outputs on a virtual external clock '%s'\n", virtual_clock_name.c_str());
1798	    VTR_LOG("   * optimize all netlist and virtual clocks to run as fast as possible\n");
1799	    VTR_LOG("   * ignore cross netlist clock domain timing paths\n");
1800	
1801	    //Create a virtual clock, with 0 period
1802	    tatum::DomainId virtual_clock = tc.create_clock_domain(virtual_clock_name);
1803	    tc.set_setup_constraint(virtual_clock, virtual_clock, tatum::Time(0.));
1804	    tc.set_hold_constraint(virtual_clock, virtual_clock, tatum::Time(0.));
1805	
1806	    //Constrain all I/Os with zero input/output delay t the virtual clock
1807	    constrain_all_ios(netlist, lookup, tc, virtual_clock, virtual_clock, tatum::Time(0.), tatum::Time(0.));
1808	
1809	    //Create each of the netlist clocks, and constrain it to period 0. Do not analyze cross-domain paths
1810	    for (AtomPinId clock_driver : clock_drivers) {
1811	        AtomNetId clock_net = netlist.pin_net(clock_driver);
1812	
1813	        //Create the clock
1814	        std::string clock_name = netlist.net_name(clock_net);
1815	        tatum::DomainId clock = tc.create_clock_domain(clock_name);
1816	
1817	        //Mark the clock domain source
1818	        tatum::NodeId clock_source = lookup.atom_pin_tnode(clock_driver);
1819	        VTR_ASSERT(clock_source);
1820	        tc.set_clock_domain_source(clock_source, clock);
1821	
1822	        //Do not analyze cross-domain timing paths (except to/from virtual clock)
1823	        tc.set_setup_constraint(clock, clock, tatum::Time(0.));         //Intra-domain
1824	        tc.set_setup_constraint(clock, virtual_clock, tatum::Time(0.)); //netlist to virtual
1825	        tc.set_setup_constraint(virtual_clock, clock, tatum::Time(0.)); //virtual to netlist
1826	
1827	        tc.set_hold_constraint(clock, clock, tatum::Time(0.));         //Intra-domain
1828	        tc.set_hold_constraint(clock, virtual_clock, tatum::Time(0.)); //netlist to virtual
1829	        tc.set_hold_constraint(virtual_clock, clock, tatum::Time(0.)); //virtual to netlist
1830	    }
1831	
1832	    //Mark constant generator timing nodes
1833	    mark_constant_generators(netlist, lookup, tc);
1834	}
1835	
1836	//Look through the netlist to find any constant generators, and mark them as
1837	//constant generators in the timing constraints
1838	void mark_constant_generators(const AtomNetlist& netlist,
1839	                              const AtomLookup& lookup,
1840	                              tatum::TimingConstraints& tc) {
1841	    for (AtomPinId pin : netlist.pins()) {
1842	        if (netlist.pin_is_constant(pin)) {
1843	            tatum::NodeId tnode = lookup.atom_pin_tnode(pin);
1844	            VTR_ASSERT(tnode);
1845	
1846	            tc.set_constant_generator(tnode);
1847	        }
1848	    }
1849	}
1850	
1851	//Constrain all primary inputs and primary outputs to the specified clock domains and delays
1852	void constrain_all_ios(const AtomNetlist& netlist,
1853	                       const AtomLookup& lookup,
1854	                       tatum::TimingConstraints& tc,
1855	                       tatum::DomainId input_domain,
1856	                       tatum::DomainId output_domain,
1857	                       tatum::Time input_delay,
1858	                       tatum::Time output_delay) {
1859	    for (AtomBlockId blk : netlist.blocks()) {
1860	        AtomBlockType type = netlist.block_type(blk);
1861	
1862	        if (type == AtomBlockType::INPAD || type == AtomBlockType::OUTPAD) {
1863	            //Get the pin
1864	            if (netlist.block_pins(blk).size() == 1) {
1865	                AtomPinId pin = *netlist.block_pins(blk).begin();
1866	
1867	                //Find the associated tnode
1868	                tatum::NodeId tnode = lookup.atom_pin_tnode(pin);
1869	
1870	                //Constrain it
1871	                if (type == AtomBlockType::INPAD) {
1872	                    tc.set_input_constraint(tnode, input_domain, tatum::DelayType::MAX, input_delay);
1873	                    tc.set_input_constraint(tnode, input_domain, tatum::DelayType::MIN, input_delay);
1874	                } else {
1875	                    VTR_ASSERT(type == AtomBlockType::OUTPAD);
1876	                    tc.set_output_constraint(tnode, output_domain, tatum::DelayType::MAX, output_delay);
1877	                    tc.set_output_constraint(tnode, output_domain, tatum::DelayType::MIN, output_delay);
1878	                }
1879	            } else {
1880	                VTR_ASSERT_MSG(netlist.block_pins(blk).size() == 0, "Unconnected I/O");
1881	            }
1882	        }
1883	    }
1884	}
1885	
1886	std::map<std::string, AtomPinId> find_netlist_primary_ios(const AtomNetlist& netlist) {
1887	    std::map<std::string, AtomPinId> primary_inputs;
1888	
1889	    for (AtomBlockId blk : netlist.blocks()) {
1890	        auto type = netlist.block_type(blk);
1891	        if (type == AtomBlockType::INPAD || type == AtomBlockType::OUTPAD) {
1892	            VTR_ASSERT(netlist.block_pins(blk).size() == 1);
1893	            AtomPinId pin = *netlist.block_pins(blk).begin();
1894	
1895	            std::string orig_name = orig_blif_name(netlist.block_name(blk));
1896	
1897	            VTR_ASSERT(!primary_inputs.count(orig_name));
1898	
1899	            primary_inputs[orig_name] = pin;
1900	        }
1901	    }
1902	
1903	    return primary_inputs;
1904	}
1905	
1906	//Trim off the prefix added to blif names to make outputs unique
1907	std::string orig_blif_name(std::string name) {
1908	    constexpr const char* BLIF_UNIQ_PREFIX = "out:";
1909	
1910	    if (name.find(BLIF_UNIQ_PREFIX) == 0) {                    //Starts with prefix
1911	        name = vtr::replace_first(name, BLIF_UNIQ_PREFIX, ""); //Remove prefix
1912	    }
1913	
1914	    return name;
1915	}
1916	
1917	//Converts a glob pattern to a std::regex
1918	std::regex glob_pattern_to_regex(const std::string& glob_pattern) {
1919	    //In glob (i.e. unix-shell style):
1920	    //   '*' is a wildcard match of zero or more instances of any characters
1921	    //
1922	    //In regex:
1923	    //   '*' matches zero or more of the preceding character
1924	    //   '.' matches any character
1925	    //
1926	    //To convert a glob to a regex we need to:
1927	    //   Convert '.' to "\.", so literal '.' in glob is treated as literal in the regex
1928	    //   Convert '*' to ".*" so literal '*' in glob matches any sequence
1929	
1930	    std::string regex_str = vtr::replace_all(glob_pattern, ".", "\\.");
1931	    regex_str = vtr::replace_all(regex_str, "*", ".*");
1932	
1933	    return std::regex(regex_str);
1934	}
